#include <unistd.h>
#include <sys/wait.h>
#include <fcntl.h>

int main() {
    int fd[2];  // File descriptor pair for pipe
    pid_t pid;

    // Create a pipe
    if (pipe(fd) == -1) {
        std::cerr << "Pipe failed" << std::endl;
        return 1;
    }

    // Fork the process
    pid = fork();
    if (pid == -1) {
        std::cerr << "Fork failed" << std::endl;
        return 1;
    }

    if (pid == 0) {  // Child process
        // Close unused ends of the pipe
        close(fd[1]);  // Close write end in child

        // Redirect stdin and stdout to the read end of the pipe
        dup2(fd[0], STDIN_FILENO);
        dup2(fd[0], STDOUT_FILENO);

        // Close the read end of the pipe
        close(fd[0]);

        // Execute the new process
